class Solution:
    def maxChunksToSorted(self, arr):
        n = len(arr)
        suffix_min = [0] * (n + 1)
        suffix_min[n] = float('inf')
        for i in range(n - 1, -1, -1):
            suffix_min[i] = min(arr[i], suffix_min[i + 1])
        chunks = 0
        prefix_max = float('-inf')
        for i in range(n):
            prefix_max = max(prefix_max, arr[i])
            if prefix_max <= suffix_min[i + 1]:
                chunks += 1
        return chunks

