class Solution:
    def maxChunksToSorted(self, arr):
        stack = []
        for v in arr:
            if stack and v < stack[-1]:
                top = stack.pop()
                while stack and v < stack[-1]:
                    stack.pop()
                stack.append(top)
            else:
                stack.append(v)
        return len(stack)

